1	/** Minimal substitution surface, satisfied by SharedCredentialRegistry. */
2	export interface Replacer {
3	  replaceAll(input: string): string;
4	  replaceAllBuffer(input: Buffer): Buffer;
5	}
6	
7	/** First canary token present in `data`, or null. Mirrors the listener's existing `includes` scan. */
8	export function findCanaryHit(data: string | Buffer, tokens: readonly string[]): string | null {
9	  if (tokens.length === 0) return null;
10	  const hay = typeof data === 'string' ? data : data.toString('latin1');
11	  for (const token of tokens) {
12	    if (token && hay.includes(token)) return token;
13	  }
14	  return null;
15	}
16	
17	export interface HeadTransform {
18	  head: Buffer;
19	  canaryToken: string | null;
20	}
21	
22	// Matches `Authorization: Basic <b64>` / `Proxy-Authorization: Basic <b64>` (scheme case-insensitive).
23	const BASIC_AUTH_LINE_RE = /^((?:proxy-)?authorization):[ \t]*(basic)[ \t]+([A-Za-z0-9+/=]+)[ \t]*$/i;
24	
25	/**
26	 * Decode → canary-scan → substitute → re-encode each Basic auth header in an HTTP
27	 * request head. All other bytes (including Bearer/Digest auth) are preserved 1:1
28	 * (latin1 round-trip). Re-encoding to base64 cannot emit CR/LF, so a malicious
29	 * decoded value cannot inject headers. If a canary token appears in any decoded
30	 * value, returns `{ canaryToken }` and leaves the head unmodified (caller blocks).
31	 */
32	export function transformBasicAuthHead(
33	  head: Buffer,
34	  replacer: Replacer,
35	  canaryTokens: readonly string[],
36	): HeadTransform {
37	  const lines = head.toString('latin1').split('\r\n');
38	  let mutated = false;
39	  for (let i = 0; i < lines.length; i++) {
40	    const line = lines[i];
41	    if (line === undefined) continue;
42	    const m = line.match(BASIC_AUTH_LINE_RE);
43	    if (!m) continue;
44	    const name = m[1]!;
45	    const scheme = m[2]!;
46	    const b64 = m[3]!;
47	    const decoded = Buffer.from(b64, 'base64').toString('utf8');
48	    const hit = findCanaryHit(decoded, canaryTokens);
49	    if (hit) return { head, canaryToken: hit };
50	    const replaced = replacer.replaceAll(decoded);
51	    if (replaced !== decoded) {
52	      lines[i] = `${name}: ${scheme} ${Buffer.from(replaced, 'utf8').toString('base64')}`;
53	      mutated = true;
54	    }
55	  }
56	  if (!mutated) return { head, canaryToken: null };
57	  return { head: Buffer.from(lines.join('\r\n'), 'latin1'), canaryToken: null };
58	}
59	
60	const DEFAULT_MAX_HEAD = 64 * 1024;
61	
62	export interface FramerOptions {
63	  /** Cap on a single buffered request head; exceeding it falls back to verbatim passthrough. */
64	  maxHeadBytes?: number;
65	  /** Called once when a head exceeds `maxHeadBytes` (for logging). */
66	  onOversizedHead?: () => void;
67	}
68	
69	export interface FramerOutput {
70	  /** Bytes to forward upstream (may be empty while a head is still buffering). */
71	  out: Buffer;
72	  /** Non-null if a canary token appeared in a decoded Basic value — caller must block. */
73	  canaryToken: string | null;
74	}
75	
76	type Phase = 'head' | 'body-counted' | 'passthrough';
77	
78	function indexOfCrlfCrlf(buf: Buffer): number {
79	  return buf.indexOf('\r\n\r\n', 0, 'latin1');
80	}
81	
82	interface BodyFraming {
83	  contentLength: number;
84	  chunked: boolean;
85	}
86	
87	function parseBodyFraming(head: Buffer): BodyFraming {
88	  let contentLength = 0;
89	  let chunked = false;
90	  for (const line of head.toString('latin1').split('\r\n')) {
91	    const c = line.match(/^content-length:[ \t]*(\d+)[ \t]*$/i);
92	    if (c) contentLength = Number(c[1]!);
93	    const te = line.match(/^transfer-encoding:[ \t]*(.+?)[ \t]*$/i);
94	    if (te && /\bchunked\b/i.test(te[1]!)) chunked = true;
